import React, {useEffect, useRef, useState} from "react";
import {createPortal} from "react-dom";
import {Heart, Palette, Sparkles} from "lucide-react";
import {AVAILABLE_ICONS, THEME_COLORS} from "./Constants";

function IconColorPicker({
    paramKey,
    currentIcon,
    currentColor,
    onSelectIcon,
    onSelectColor,
    onClose,
    position,
    buttonRef
}) {
    const pickerRef = useRef(null);
    const [activeTab, setActiveTab] = useState('icon');

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (pickerRef.current && !pickerRef.current.contains(event.target)) {
                if (buttonRef.current && !buttonRef.current.contains(event.target)) {
                    onClose();
                }
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [paramKey, onClose, buttonRef]);

    return createPortal(
        <div
            ref={pickerRef}
            className="fixed z-[9999] bg-white rounded-2xl shadow-2xl border-2 border-pink-200 w-80"
            style={{ top: `${position.top}px`, left: `${position.left}px` }}
        >
            {/* 标签页头部 */}
            <div className="flex border-b-2 border-pink-100">
                <button
                    onClick={() => setActiveTab('icon')}
                    className={`flex-1 py-3 font-bold text-sm transition-all ${
                        activeTab === 'icon'
                            ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                            : 'text-gray-400 hover:text-gray-600'
                    }`}
                >
                    <Sparkles className="inline-block mr-1" size={14} />
                    选择图标
                </button>
                <button
                    onClick={() => setActiveTab('color')}
                    className={`flex-1 py-3 font-bold text-sm transition-all ${
                        activeTab === 'color'
                            ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                            : 'text-gray-400 hover:text-gray-600'
                    }`}
                >
                    <Palette className="inline-block mr-1" size={14} />
                    选择颜色
                </button>
            </div>

            {/* 内容区域 */}
            <div className="p-4">
                {activeTab === 'icon' ? (
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-gray-700">当前图标预览</span>
                            <div className={`p-2 rounded-lg bg-gradient-to-br ${THEME_COLORS[currentColor].gradient}`}>
                                {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 24 })}
                            </div>
                        </div>
                        <div className="grid grid-cols-6 gap-2 max-h-64 overflow-y-auto pr-1 scrollbar-thin scrollbar-thumb-pink-200 scrollbar-track-gray-100">
                            {Object.entries(AVAILABLE_ICONS).map(([name, Icon]) => (
                                <button
                                    key={name}
                                    onClick={() => onSelectIcon(name)}
                                    className={`p-2 rounded-lg transition-all hover:scale-110 ${
                                        currentIcon === name
                                            ? `bg-gradient-to-br ${THEME_COLORS[currentColor].gradient} text-white shadow-lg ring-2 ring-pink-300`
                                            : 'bg-gray-100 text-gray-600 hover:bg-pink-100'
                                    }`}
                                    title={name}
                                >
                                    <Icon size={20} />
                                </button>
                            ))}
                        </div>
                    </div>
                ) : (
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-gray-700">当前颜色预览</span>
                            <div className={`p-2 rounded-lg bg-gradient-to-br ${THEME_COLORS[currentColor].gradient}`}>
                                {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 24 })}
                            </div>
                        </div>
                        <div className="grid grid-cols-3 gap-3">
                            {THEME_COLORS.map((color, index) => (
                                <button
                                    key={index}
                                    onClick={() => onSelectColor(index)}
                                    className={`relative group transition-all hover:scale-105 ${
                                        currentColor === index ? 'scale-110' : ''
                                    }`}
                                >
                                    <div className={`h-16 rounded-xl bg-gradient-to-br ${color.gradient} shadow-lg transition-all ${
                                        currentColor === index ? 'ring-4 ring-pink-300 shadow-xl' : 'hover:shadow-xl'
                                    }`}>
                                        <div className="h-full flex items-center justify-center">
                                            {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 28 })}
                                        </div>
                                    </div>
                                    <div className="mt-1 text-xs font-semibold text-gray-600 text-center">
                                        {color.name}
                                    </div>
                                    {currentColor === index && (
                                        <div className="absolute -top-1 -right-1">
                                            <Heart className="text-pink-500 fill-pink-500 animate-pulse" size={16} />
                                        </div>
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* 底部关闭按钮 */}
            <div className="border-t-2 border-pink-100 p-3">
                <button
                    onClick={onClose}
                    className="w-full py-2 bg-gradient-to-r from-pink-400 to-purple-400 text-white font-bold rounded-xl hover:shadow-lg transition-all hover:scale-105"
                >
                    完成 ♡
                </button>
            </div>
        </div>,
        document.body
    );
}

export default IconColorPicker
